def prof_pages():
    urls = []
    for slug, name, gen_name, intro, mix, income, faqs in PROF:
        rate = {"fiz": 0.04, "jur": 0.06, "mixed": 0.05}[mix]
        mix_txt = {"fiz": "в основном физлица — базовая ставка 4%",
                   "jur": "в основном юрлица и ИП — базовая ставка 6%",
                   "mixed": "и физлица (4%), и юрлица (6%)"}[mix]
        tax = income * rate
        tax_d = income * (rate - (0.01 if mix == "fiz" else 0.02 if mix == "jur" else 0.015))
        months_to_limit = 2400000 // income
        faq_html = "".join(f"<details><summary>{html.escape(q)}</summary><p>{html.escape(a)}</p></details>" for q, a in faqs)
        faq_ld_items = ",".join(
            '{"@type":"Question","name":%s,"acceptedAnswer":{"@type":"Answer","text":%s}}' % (
                __import__("json").dumps(q, ensure_ascii=False), __import__("json").dumps(a, ensure_ascii=False))
            for q, a in faqs)
        jsonld = '{"@context":"https://schema.org","@type":"FAQPage","mainEntity":[%s]}' % faq_ld_items
        body = f"""
<p>{html.escape(intro)}</p>
<h2>Ставка налога</h2>
<p>Клиенты у {html.escape(gen_name)} — {mix_txt}. Ставки НПД: <b>4%</b> с доходов от физлиц и <b>6%</b> от юрлиц и ИП. Пока не израсходован разовый вычет 10 000 ₽, ставки автоматически снижены до 3% и 4%.</p>
<h2>Пример расчёта</h2>
<p>Допустим, доход {html.escape(gen_name)} за месяц — <b>{fmt(income)} ₽</b>:</p>
<table>
<tr><th>Показатель</th><th class="num">Сумма</th></tr>
<tr><td>Налог по базовой ставке</td><td class="num">≈ {fmt(tax)} ₽</td></tr>
<tr><td>Налог, пока действует вычет</td><td class="num">≈ {fmt(tax_d)} ₽</td></tr>
<tr><td>Останется на руках (без вычета)</td><td class="num">≈ {fmt(income - tax)} ₽</td></tr>
</table>
<p>При таком доходе годовой лимит НПД 2,4 млн ₽ исчерпается примерно за {months_to_limit} мес. Налог начисляется в «Мой налог» до 12-го числа следующего месяца, оплатить нужно до 28-го.</p>
<h2>Частые вопросы</h2>
{faq_html}
"""
        title = f"Налог самозанятого для {gen_name} в 2026: ставка, пример расчёта"
        desc = f"Сколько налога платит {name} на НПД: ставки 4% и 6%, пример с дохода {fmt(income)} ₽, вычет 10 000 ₽, лимит 2,4 млн. Понятно и с примерами."
        urls.append((page(f"npd/{slug}", title, desc,
                          f"Налог самозанятого для {gen_name}: сколько платить и как считать",
                          name.capitalize(), body, related_for("prof", slug), jsonld),
                     f"Налог для {gen_name}", f"/samoschet/npd/{slug}/"))
    return urls

# ------------------------------------------------------------------- amounts
AMOUNTS = [5000,10000,15000,20000,25000,30000,35000,40000,45000,50000,60000,70000,80000,90000,100000,120000,150000,200000,250000,300000]

def amount_pages():
    urls = []
    for a in AMOUNTS:
        t4, t6 = a*0.04, a*0.06
        t3, t4j = a*0.03, a*0.04
        months = 2400000 / a
        body = f"""
<p>Быстрый ответ: с дохода <b>{fmt(a)} ₽</b> самозанятый заплатит <b>{fmt(t4)} ₽</b> (если платили физлица) или <b>{fmt(t6)} ₽</b> (если юрлица или ИП). Пока не израсходован налоговый вычет — меньше: {fmt(t3)} ₽ и {fmt(t4j)} ₽.</p>
<table>
<tr><th>Кто заплатил вам {fmt(a)} ₽</th><th class="num">Ставка</th><th class="num">Налог</th><th class="num">На руках</th></tr>
<tr><td>Физлицо</td><td class="num">4%</td><td class="num">{fmt(t4)} ₽</td><td class="num">{fmt(a-t4)} ₽</td></tr>
<tr><td>Физлицо (действует вычет)</td><td class="num">3%</td><td class="num">{fmt(t3)} ₽</td><td class="num">{fmt(a-t3)} ₽</td></tr>
<tr><td>Юрлицо / ИП</td><td class="num">6%</td><td class="num">{fmt(t6)} ₽</td><td class="num">{fmt(a-t6)} ₽</td></tr>
<tr><td>Юрлицо / ИП (действует вычет)</td><td class="num">4%</td><td class="num">{fmt(t4j)} ₽</td><td class="num">{fmt(a-t4j)} ₽</td></tr>
</table>
<h2>Как это работает</h2>
<p>Налог на профессиональный доход считается автоматически: вы формируете чек на каждую оплату в приложении «Мой налог», до 12-го числа следующего месяца приходит начисление, заплатить нужно до 28-го числа. Никаких деклараций и обязательных взносов нет.</p>
<p>Разовый вычет 10 000 ₽ применяется сам: ставка снижается с 4% до 3% и с 6% до 4%, пока вычет не израсходуется. С дохода {fmt(a)} ₽ от физлиц вычет «съедает» {fmt(a*0.01)} ₽ налога.</p>
<h2>Если {fmt(a)} ₽ — это ваш месячный доход</h2>
<p>За год выйдет {fmt(a*12)} ₽. Годовой лимит НПД — 2 400 000 ₽: при таком темпе его хватит примерно на {months:.0f} мес.{" Лимит вам не грозит." if months>=12 else " <b>Лимит закончится раньше конца года</b> — заранее продумайте переход на ИП с УСН."}</p>
<div class="note">Личные переводы, кэшбэк и возвраты налогом не облагаются — платите только с дохода от клиентов. Не отдавайте 4% с перевода от мамы.</div>
"""
        title = f"Налог самозанятого с {fmt(a)} ₽ в 2026 — точный расчёт"
        desc = f"С {fmt(a)} ₽ самозанятый платит {fmt(t4)} ₽ (4%, физлица) или {fmt(t6)} ₽ (6%, юрлица). С вычетом — {fmt(t3)} ₽ и {fmt(t4j)} ₽. Таблица и пояснение."
        urls.append((page(f"nalog/{a}", title, desc,
                          f"Сколько налога заплатит самозанятый с {fmt(a)} ₽",
                          f"Налог с {fmt(a)} ₽", body, related_for("amount", a)),
                     f"Налог с {fmt(a)} ₽", f"/samoschet/nalog/{a}/"))
    return urls

