def qa_pages():
    import json as _json
    urls = []
    for slug, q, short, body_extra in QA:
        jsonld = _json.dumps({"@context":"https://schema.org","@type":"FAQPage","mainEntity":[{"@type":"Question","name":q,"acceptedAnswer":{"@type":"Answer","text":short}}]}, ensure_ascii=False)
        body = f"<p><b>Короткий ответ:</b> {html.escape(short)}</p><h2>Подробнее</h2>{body_extra}"
        title = q + " — разбор 2026"
        urls.append((page(f"vopros/{slug}", title, short[:158], q, "Вопрос", body, related_for("qa", slug), jsonld),
                     q, f"/samoschet/vopros/{slug}/"))
    return urls

