# ------------------------------------------------------------ related linking
def related_for(kind, key):
    """5 связанных ссылок: детерминированная ротация по хэшу ключа."""
    pool = []
    pool += [(f"Налог для {p[2]}", f"/samoschet/npd/{p[0]}/") for p in PROF]
    pool += [(f"Налог с {fmt(a)} ₽", f"/samoschet/nalog/{a}/") for a in AMOUNTS]
    pool += [(q[1], f"/samoschet/vopros/{q[0]}/") for q in QA]
    pool += [(f"Выписка из {b[1]}", f"/samoschet/vypiska/{b[0]}/") for b in BANKS]
    h = abs(hash(f"{kind}:{key}")) % len(pool)
    picked, i = [], h
    self_frag = f"/{key}/" if not isinstance(key, int) else f"/{key}/"
    while len(picked) < 5:
        cand = pool[i % len(pool)]
        if self_frag not in cand[1]:
            picked.append(cand)
        i += 7  # шаг-простое число, чтобы ходить по всему пулу
    return picked

# ----------------------------------------------------------------------- hub
def hub(all_urls):
    groups = {"Профессии": [], "Сколько налога с суммы": [], "Вопросы и ответы": [], "Выписки из банков": []}
    for canon, t, path in all_urls:
        if "/npd/" in path: groups["Профессии"].append((t, path))
        elif "/nalog/" in path: groups["Сколько налога с суммы"].append((t, path))
        elif "/vopros/" in path: groups["Вопросы и ответы"].append((t, path))
        elif "/vypiska/" in path: groups["Выписки из банков"].append((t, path))
    secs = ""
    for g, items in groups.items():
        lis = "".join(f'<li><a style="color:var(--red);text-decoration:none" href="{u}">{html.escape(t)}</a></li>' for t, u in items)
        secs += f"<h2>{g}</h2><ul>{lis}</ul>"
    body = f"""
<p>Справочник по налогу на профессиональный доход: ставки, лимиты, чеки, частные случаи по профессиям и готовые расчёты по суммам. Всё коротко и с цифрами.</p>
{secs}
"""
    return page("baza", "База знаний самозанятого: налог НПД, чеки, лимиты — Самосчёт",
         "Справочник самозанятого: сколько налога с вашей суммы, ставки по профессиям, ответы на частые вопросы про НПД, инструкции по выгрузке выписок из банков.",
         "База знаний самозанятого", "Оглавление", body, [])

# ------------------------------------------------------------------- sitemap
def sitemap(urls):
    entries = "".join(f"<url><loc>{u}</loc><lastmod>{TODAY}</lastmod></url>" for u in urls)
    xml = f'<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">{entries}</urlset>'
    with open(os.path.join(ROOT, "sitemap.xml"), "w", encoding="utf-8") as f:
        f.write(xml)

def robots():
    with open(os.path.join(ROOT, "robots.txt"), "w", encoding="utf-8") as f:
        f.write(f"User-agent: *\nAllow: /\nSitemap: {SITE}/sitemap.xml\n")

