    all_urls += amount_pages()
    all_urls += qa_pages()
    all_urls += bank_pages()
    hub_url = hub(all_urls)
    canon_list = [SITE + "/", SITE + "/app.html", hub_url] + [u[0] for u in all_urls]
    sitemap(canon_list)
    robots()
    print(f"generated {len(all_urls)} pages + hub; sitemap has {len(canon_list)} urls")
